const update = items[0]?.json ?? {};
const message = update.message ?? update.edited_message ?? null;
if (!message) return [];

const rawText = String(message.text ?? '').trim();
if (!rawText) return [];

const [firstToken = '', secondToken = ''] = rawText.split(/\s+/);
const normalizedFirst = firstToken.split('@')[0].toLowerCase();
if (normalizedFirst !== '/ops') {
  return [];
}

const requested = secondToken.trim().toLowerCase() || 'help';
const commandMap = {
  help: 'status.help',
  version: 'status.version',
  drift: 'status.drift',
  overview: 'status.overview',
};

const actorId = String(message.chat?.id ?? '');
if (!actorId) {
  return [];
}

const actorName = message.from?.username || [message.from?.first_name, message.from?.last_name].filter(Boolean).join(' ') || 'telegram';

return [{
  json: {
    reply_chat_id: actorId,
    actor_id: actorId,
    actor_name: actorName,
    raw_text: rawText,
    requested_command: requested,
    command: commandMap[requested] || `status.${requested}`,
  },
}];

const payload = items[0]?.json ?? {};
const requestId = `ops-${Date.now()}`;
const baseUrl = '__OPS_PUBLIC_BASE_URL__'.replace(/\/$/, '');
const secret = '__OPS_COMMAND_SHARED_SECRET__';

async function main() {
  try {
    const response = await fetch(`${baseUrl}/api/proxy/ops/command`, {
      method: 'POST',
      headers: {
        'content-type': 'application/json',
        'x-ops-command-secret': secret,
      },
      body: JSON.stringify({
        command: payload.command,
        arguments: {},
        request_id: requestId,
        source: 'n8n',
        actor: {
          id: payload.actor_id,
          name: payload.actor_name,
          channel: 'telegram',
          role: 'read_only',
        },
      }),
    });

    let apiPayload;
    try {
      apiPayload = await response.json();
    } catch (error) {
      apiPayload = {
        ok: false,
        summary: 'Invalid backend response',
        details: [String(error?.message ?? error)],
      };
    }

    return [{
      json: {
        ...payload,
        request_id: requestId,
        backend_status: response.status,
        api_payload: apiPayload,
      },
    }];
  } catch (error) {
    return [{
      json: {
        ...payload,
        request_id: requestId,
        backend_status: 0,
        api_payload: {
          ok: false,
          summary: 'Ops command request failed',
          details: [String(error?.message ?? error)],
          severity: 'critical',
        },
      },
    }];
  }
}

return await main();

const payload = items[0]?.json ?? {};
const api = payload.api_payload ?? {};
const lines = [];

if (payload.raw_text) {
  lines.push(`요청: ${payload.raw_text}`);
}
if (api.summary) {
  lines.push(String(api.summary));
}

const details = Array.isArray(api.details) ? api.details.slice(0, 8) : [];
for (const detail of details) {
  lines.push(`- ${String(detail)}`);
}
if (!details.length && payload.backend_status && payload.backend_status !== 200) {
  lines.push(`- backend_status=${payload.backend_status}`);
}

return [{
  json: {
    reply_chat_id: payload.reply_chat_id,
    reply_text: lines.join('\n').slice(0, 3500),
  },
}];
